export declare const TOOLTIP_STYLES = "\n:host {\n    position: fixed;\n    top: 0;\n    left: 0;\n    z-index: 2147483647;\n    display: block;\n    width: 330px;\n    visibility: hidden;\n    pointer-events: none;\n    user-select: none;\n    color: #f5f5f5;\n    font-family: \"Kanit\", system-ui, sans-serif;\n    contain: layout style;\n}\n\n:host([open]) {\n    visibility: visible;\n}\n\n*, *::before, *::after {\n    box-sizing: border-box;\n}\n\n.tooltip {\n    position: relative;\n    width: 330px;\n    overflow: hidden;\n    border: 1px solid #2a2a2e;\n    border-radius: 16px;\n    background: #111111;\n    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.7);\n}\n\n.background,\n.glow {\n    position: absolute;\n    z-index: 0;\n    pointer-events: none;\n    animation: bz-tooltip-pulse 2s ease-in-out infinite;\n}\n\n.background {\n    top: 0;\n    left: 0;\n    width: 330px;\n}\n\n.glow {\n    top: -20px;\n    right: -80px;\n    width: 300px;\n    height: 200px;\n    object-fit: contain;\n    opacity: 0.4;\n    filter: blur(40px);\n}\n\n.header,\n.details {\n    position: relative;\n    z-index: 1;\n}\n\n.header {\n    display: flex;\n    gap: 12px;\n    padding: 12px;\n}\n\n.title-wrap {\n    display: flex;\n    flex: 1;\n    min-width: 0;\n    margin-right: 14px;\n    flex-direction: column;\n    justify-content: center;\n    gap: 4px;\n}\n\n.title {\n    overflow-wrap: anywhere;\n    font-size: 20px;\n    line-height: 1.375;\n}\n\n.category {\n    color: #46ecd5;\n    font-size: 10px;\n    line-height: 1;\n}\n\n.item-image {\n    width: 90px;\n    height: 90px;\n    flex: 0 0 auto;\n    object-fit: contain;\n}\n\n.details {\n    display: flex;\n    padding: 12px;\n    flex-direction: column;\n    gap: 6px;\n}\n\n.description {\n    margin-bottom: 8px;\n    color: #838383;\n    font-size: 14px;\n    line-height: 1.45;\n    overflow-wrap: anywhere;\n    white-space: pre-line;\n}\n\n.description highlight {\n    color: #46ecd5;\n}\n\n.row {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    gap: 8px;\n    padding: 2px 8px;\n    border-radius: 12px;\n    background: rgba(31, 31, 31, 0.63);\n    font-size: 14px;\n    line-height: 1.45;\n}\n\n.row-label {\n    color: #737373;\n}\n\n.row-value {\n    min-width: 0;\n    color: #d4d4d4;\n    font-weight: 500;\n    text-align: right;\n    overflow-wrap: anywhere;\n    font-variant-numeric: tabular-nums;\n}\n\n.metadata-title {\n    margin-top: 4px;\n    color: #46ecd5;\n    font-size: 11px;\n}\n\n@keyframes bz-tooltip-pulse {\n    0%, 100% { opacity: 0.45; }\n    50% { opacity: 0.8; }\n}\n\n@media (prefers-reduced-motion: reduce) {\n    .background,\n    .glow {\n        animation: none;\n    }\n}\n";
